import { useEffect, useRef, useState } from 'react';
import { useForm, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { PlusIcon, TrashIcon, SparklesIcon } from '@heroicons/react/24/outline';
import { api } from '../../../utils/api';
import { Input } from '../../../components/ui/Input';
import { Button } from '../../../components/ui/Button';
import type { Category } from '../../../types/product.types';
import toast from 'react-hot-toast';
import { useSocket } from '../../../hooks/useSocket';

const productSchema = z.object({
  name: z.string().min(3, 'Product name must be at least 3 characters'),
  description: z.string().min(20, 'Description must be at least 20 characters'),
  price: z.number({ invalid_type_error: 'Price must be a number' }).positive('Price must be positive'),
  compareAtPrice: z.number().positive().optional(),
  categoryId: z.string().min(1, 'Category is required'),
  sku: z.string().min(3, 'SKU is required'),
  inventory: z.number().int().min(0, 'Inventory must be 0 or more'),
  weight: z.number().positive().optional(),
  tags: z.string().optional(),
  attributes: z.array(
    z.object({
      name: z.string().min(1),
      values: z.string().min(1),
    }),
  ).optional(),
});

type ProductFormValues = z.infer<typeof productSchema>;

interface ProductFormProps {
  productId?: string;
  initialValues?: Partial<ProductFormValues>;
  onSuccess?: () => void;
}

export function ProductForm({ productId, initialValues, onSuccess }: ProductFormProps) {
  const queryClient = useQueryClient();
  const isEditing = Boolean(productId);
  const { on, EVENTS } = useSocket();

  const [isGenerating, setIsGenerating] = useState(false);
  const aiTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const { data: categories } = useQuery({
    queryKey: ['categories', 'tree'],
    queryFn: () => api.get<Category[]>('/categories/tree').then((r) => r.data),
    staleTime: 1000 * 60 * 60,
  });

  const {
    register,
    handleSubmit,
    control,
    setValue,
    getValues,
    formState: { errors },
  } = useForm<ProductFormValues>({
    resolver: zodResolver(productSchema),
    defaultValues: {
      inventory: 0,
      attributes: [],
      ...initialValues,
    },
  });

  const { fields: attrFields, append: appendAttr, remove: removeAttr } = useFieldArray({
    control,
    name: 'attributes',
  });

  // ── Socket.io listener ─────────────────────────────────────────────────────
  useEffect(() => {
    const unsubscribe = on(EVENTS.AI_DESCRIPTION_READY, (payload) => {
      const data = payload as { success: boolean; description?: string; error?: string };
      if (aiTimeoutRef.current) clearTimeout(aiTimeoutRef.current);
      setIsGenerating(false);

      if (data.success && data.description) {
        setValue('description', data.description, { shouldValidate: true });
        toast.success('Description generated by AI!');
      } else {
        toast.error(data.error ?? 'AI generation failed');
      }
    });
    return () => {
      unsubscribe();
      if (aiTimeoutRef.current) clearTimeout(aiTimeoutRef.current);
    };
  }, [on, setValue]); // on is now stable (useCallback); setValue is stable (useForm)

  // ── AI mutation ────────────────────────────────────────────────────────────
  const aiMutation = useMutation({
    mutationFn: () => {
      const { name, categoryId } = getValues();

      if (!name || name.length < 2) {
        throw new Error('Fill in the product name first');
      }
      const selectedCategory = categories?.find((c) => c.id === categoryId);

      return api.post('/ai/generate-description', {
        name,
        category: selectedCategory?.name ?? categoryId ?? 'General',
        features: '',
      }).then((r) => r.data);
    },
    onMutate: () => setIsGenerating(true),
    onSuccess: () => {
      // Safety fallback: if the socket event never arrives, clear the spinner after 30s
      aiTimeoutRef.current = setTimeout(() => {
        setIsGenerating(false);
        toast.error('AI is taking too long — please try again.');
      }, 30_000);
    },
    onError: (err: { message?: string; response?: { data?: { message?: string } } }) => {
      if (aiTimeoutRef.current) clearTimeout(aiTimeoutRef.current);
      setIsGenerating(false);
      toast.error(err.response?.data?.message ?? err.message ?? 'Failed to start AI generation');
    },
  });

  const saveMutation = useMutation({
    mutationFn: (values: ProductFormValues) => {
      const payload = {
        ...values,
        tags: values.tags ? values.tags.split(',').map((t) => t.trim()).filter(Boolean) : [],
        attributes: values.attributes?.map((a) => ({
          name: a.name,
          values: a.values.split(',').map((v) => v.trim()).filter(Boolean),
        })),
      };
      return isEditing
        ? api.patch(`/products/${productId}`, payload).then((r) => r.data)
        : api.post('/products', payload).then((r) => r.data);
    },
    onSuccess: () => {
      toast.success(isEditing ? 'Product updated!' : 'Product created!');
      queryClient.invalidateQueries({ queryKey: ['vendor', 'products'] });
      onSuccess?.();
    },
    onError: (err: { response?: { data?: { message?: string } } }) => {
      toast.error(err.response?.data?.message ?? 'Failed to save product');
    },
  });

  return (
    <form onSubmit={handleSubmit((v) => saveMutation.mutate(v))} className="space-y-6">
      {/* Basic info */}
      <div className="space-y-4">
        <h3 className="font-semibold text-surface-900">Basic Information</h3>

        <Input
          label="Product Name *"
          {...register('name')}
          error={errors.name?.message}
          placeholder="Enter product name"
        />

        <div>
          <div className="flex items-center justify-between mb-1.5">
            <label className="block text-sm font-medium text-surface-700">
              Description *
            </label>
            {/* AI Generate button — calls Gemini via BullMQ queue */}
            <button
              type="button"
              onClick={() => aiMutation.mutate()}
              disabled={isGenerating}
              className="flex items-center gap-1.5 text-xs font-semibold px-2.5 py-1 rounded-lg bg-gradient-to-r from-purple-100 to-primary-100 text-purple-700 hover:from-purple-200 hover:to-primary-200 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
            >
              <SparklesIcon className="w-3.5 h-3.5" />
              {isGenerating ? 'Generating…' : '✨ Generate with AI'}
            </button>
          </div>

          {/* AI status banner — shown while waiting for Socket.io response */}
          {isGenerating && (
            <div className="mb-2 flex items-center gap-2 px-3 py-2 bg-primary-50 border border-primary-200 rounded-lg text-xs text-primary-700">
              <svg className="animate-spin w-3.5 h-3.5 flex-shrink-0" viewBox="0 0 24 24" fill="none">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
              </svg>
              AI is writing your description — it will appear automatically when done.
            </div>
          )}

          <textarea
            {...register('description')}
            rows={5}
            placeholder="Describe your product in detail, or click 'Generate with AI' above..."
            className="w-full px-3 py-2.5 border border-surface-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-primary-500 resize-none"
          />
          {errors.description && (
            <p className="text-xs text-danger-600 mt-1">{errors.description.message}</p>
          )}
        </div>

        <div>
          <label className="block text-sm font-medium text-surface-700 mb-1.5">Category *</label>
          <select
            {...register('categoryId')}
            className="w-full px-3 py-2.5 border border-surface-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-primary-500 bg-white"
          >
            <option value="">Select a category</option>
            {categories?.map((cat) => (
              <option key={cat.id} value={cat.id}>{cat.name}</option>
            ))}
          </select>
          {errors.categoryId && (
            <p className="text-xs text-danger-600 mt-1">{errors.categoryId.message}</p>
          )}
        </div>
      </div>

      {/* Pricing */}
      <div className="space-y-4">
        <h3 className="font-semibold text-surface-900">Pricing</h3>
        <div className="grid grid-cols-2 gap-4">
          <Input
            label="Price *"
            type="number"
            step="0.01"
            {...register('price', { valueAsNumber: true })}
            error={errors.price?.message}
            placeholder="0.00"
          />
          <Input
            label="Compare At Price"
            type="number"
            step="0.01"
            {...register('compareAtPrice', { valueAsNumber: true })}
            error={errors.compareAtPrice?.message}
            placeholder="0.00"
          />
        </div>
      </div>

      {/* Inventory */}
      <div className="space-y-4">
        <h3 className="font-semibold text-surface-900">Inventory</h3>
        <div className="grid grid-cols-2 gap-4">
          <Input
            label="SKU *"
            {...register('sku')}
            error={errors.sku?.message}
            placeholder="PROD-001"
          />
          <Input
            label="Stock Quantity *"
            type="number"
            {...register('inventory', { valueAsNumber: true })}
            error={errors.inventory?.message}
          />
        </div>
        <Input
          label="Weight (kg)"
          type="number"
          step="0.01"
          {...register('weight', { valueAsNumber: true })}
          error={errors.weight?.message}
          placeholder="0.00"
        />
      </div>

      {/* Attributes */}
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="font-semibold text-surface-900">Attributes</h3>
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={() => appendAttr({ name: '', values: '' })}
          >
            <PlusIcon className="w-4 h-4 mr-1" />
            Add Attribute
          </Button>
        </div>
        {attrFields.map((field, i) => (
          <div key={field.id} className="flex gap-3 items-start">
            <Input
              {...register(`attributes.${i}.name`)}
              placeholder="Name (e.g. Color)"
              error={errors.attributes?.[i]?.name?.message}
            />
            <Input
              {...register(`attributes.${i}.values`)}
              placeholder="Values (comma-separated)"
              error={errors.attributes?.[i]?.values?.message}
            />
            <button
              type="button"
              onClick={() => removeAttr(i)}
              className="mt-1 p-2.5 text-surface-400 hover:text-danger-500 transition-colors flex-shrink-0"
            >
              <TrashIcon className="w-4 h-4" />
            </button>
          </div>
        ))}
      </div>

      {/* Tags */}
      <div>
        <Input
          label="Tags (comma-separated)"
          {...register('tags')}
          placeholder="electronics, gadgets, wireless"
        />
      </div>

      <div className="pt-4 flex gap-3">
        <Button type="submit" isLoading={saveMutation.isPending} size="lg">
          {isEditing ? 'Save Changes' : 'Create Product'}
        </Button>
      </div>
    </form>
  );
}
